"""Redis client configuration for HealthBridge platform.

Provides a singleton Redis connection pool for session storage,
caching, and rate limiting across the application.
"""

import redis
import os
from typing import Optional


class RedisClient:
    """Managed Redis connection with health checking and reconnection."""

    _instance: Optional['RedisClient'] = None
    _pool: Optional[redis.ConnectionPool] = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._pool = redis.ConnectionPool(
                host=os.environ.get('REDIS_HOST', 'localhost'),
                port=int(os.environ.get('REDIS_PORT', 6379)),
                db=int(os.environ.get('REDIS_DB', 0)),
                password=os.environ.get('REDIS_PASSWORD', None),
                decode_responses=True,
                max_connections=20,
                socket_timeout=5,
                socket_connect_timeout=5,
            )
        return cls._instance

    @property
    def conn(self) -> redis.Redis:
        """Get a Redis connection from the pool."""
        return redis.Redis(connection_pool=self._pool)

    def health_check(self) -> bool:
        """Verify Redis connectivity."""
        try:
            return self.conn.ping()
        except redis.ConnectionError:
            return False


def get_redis() -> redis.Redis:
    """Convenience function to get a Redis connection."""
    return RedisClient().conn

"""Tests for authentication middleware."""

import pytest
import json
import time
from unittest.mock import patch, MagicMock
from flask import Flask
from middleware.auth_middleware import require_auth


@pytest.fixture
def app():
    app = Flask(__name__)
    app.config['TESTING'] = True

    @app.route('/api/patient/profile')
    @require_auth
    def protected_route():
        from flask import g
        return json.dumps({"user_id": g.session_data["user_id"]}), 200

    @app.route('/api/health')
    def health_check():
        return json.dumps({"status": "ok"}), 200

    return app


@pytest.fixture
def client(app):
    return app.test_client()


class TestRequireAuth:
    def test_missing_session_header(self, client):
        resp = client.get('/api/patient/profile')
        assert resp.status_code == 401

    def test_invalid_session_token(self, client):
        with patch('middleware.auth_middleware.SessionManager') as MockSM:
            instance = MockSM.return_value
            instance.validate_session.return_value = None
            resp = client.get(
                '/api/patient/profile',
                headers={'X-Session-Token': 'invalid_token'}
            )
            assert resp.status_code == 401

    def test_valid_session_token(self, client):
        session_data = {
            "user_id": "usr_12345",
            "roles": ["patient"],
            "ip_address": "127.0.0.1",
            "created_at": time.time(),
            "expires_at": time.time() + 28800,
            "last_activity": time.time()
        }
        with patch('middleware.auth_middleware.SessionManager') as MockSM:
            instance = MockSM.return_value
            instance.validate_session.return_value = session_data
            resp = client.get(
                '/api/patient/profile',
                headers={'X-Session-Token': 'valid_token_hex'}
            )
            assert resp.status_code == 200
            data = json.loads(resp.data)
            assert data["user_id"] == "usr_12345"

    def test_unprotected_route_accessible(self, client):
        resp = client.get('/api/health')
        assert resp.status_code == 200
